<header class="page-head"><div><span class="eyebrow">Katalog</span><h1><?=$product?'Edit produk':'Produk baru'?></h1></div><a href="<?=url('/admin/products')?>">Kembali</a></header><form method="post" enctype="multipart/form-data" action="<?=$product?url('/admin/products/'.$product['id']):url('/admin/products')?>" class="editor-grid"><?=csrf_field()?><?php if($product):?><input type="hidden" name="_method" value="PUT"><?php endif?><section class="panel stack"><h2>Informasi utama</h2><label>Nama produk<input name="name" value="<?=e($product['name']??'')?>" required></label><div class="form-grid"><label>Kategori<select name="category_id"><option value="0">Tanpa kategori</option><?php foreach($categories as $c):?><option value="<?=$c['id']?>" <?=($product['category_id']??null)==$c['id']?'selected':''?>><?=e($c['name'])?></option><?php endforeach?></select></label><label>SKU dasar<input name="base_sku" value="<?=e($product['base_sku']??'')?>"></label><label>Harga jual<input type="number" name="base_price" value="<?=e($product['base_price']??0)?>" required></label><label>Harga modal<input type="number" name="base_cost" value="<?=e($product['base_cost']??0)?>"></label><label>Satuan<input name="unit" value="<?=e($product['unit']??'pcs')?>"></label><label>Berat gram<input type="number" name="weight_grams" value="<?=e($product['weight_grams']??0)?>"></label></div><label>Deskripsi singkat<textarea name="short_description"><?=e($product['short_description']??'')?></textarea></label><label>Deskripsi lengkap<textarea name="description" rows="7"><?=e($product['description']??'')?></textarea></label><label>Galeri gambar<input type="file" name="images[]" accept="image/jpeg,image/png,image/webp" multiple><small>JPG, PNG, WebP. Maksimal 5 MB per gambar.</small></label></section><aside class="stack"><section class="panel stack"><h2>Publikasi</h2><label>Status<select name="status"><option value="active">Aktif</option><option value="inactive" <?=($product['status']??'')==='inactive'?'selected':''?>>Nonaktif</option></select></label><label class="check"><input type="checkbox" name="is_featured" value="1" <?=($product['is_featured']??0)?'checked':''?>> Produk unggulan</label><button class="button button-large">Simpan produk</button></section><section class="panel"><div class="section-title"><h2>Varian</h2><button type="button" class="text-button" onclick="addVariant()">+ Tambah</button></div><div id="variants"><?php $rows=$variants?:[['id'=>'','name'=>'Default','sku'=>'','price'=>'','cost'=>'','stock_qty'=>0,'low_stock_threshold'=>5]];foreach($rows as $i=>$v):?><div class="variant-row"><input type="hidden" name="variants[<?=$i?>][id]" value="<?=e($v['id'])?>"><label>Nama<input name="variants[<?=$i?>][name]" value="<?=e($v['name'])?>" placeholder="Hitam / L"></label><label>SKU<input name="variants[<?=$i?>][sku]" value="<?=e($v['sku'])?>" required></label><div class="form-grid"><label>Harga khusus<input type="number" name="variants[<?=$i?>][price]" value="<?=e($v['price'])?>"></label><label>Modal<input type="number" name="variants[<?=$i?>][cost]" value="<?=e($v['cost'])?>"></label><label>Stok<input type="number" name="variants[<?=$i?>][stock_qty]" value="<?=e($v['stock_qty'])?>"></label><label>Batas rendah<input type="number" name="variants[<?=$i?>][low_stock_threshold]" value="<?=e($v['low_stock_threshold'])?>"></label></div></div><?php endforeach?></div></section></aside></form><template id="variant-template"><div class="variant-row"><label>Nama<input data-name="name" placeholder="Warna / Ukuran"></label><label>SKU<input data-name="sku" required></label><div class="form-grid"><label>Harga khusus<input type="number" data-name="price"></label><label>Modal<input type="number" data-name="cost"></label><label>Stok<input type="number" data-name="stock_qty" value="0"></label><label>Batas rendah<input type="number" data-name="low_stock_threshold" value="5"></label></div></div></template><script>function addVariant(){const n=document.querySelectorAll('.variant-row').length,t=document.querySelector('#variant-template').content.cloneNode(true);t.querySelectorAll('[data-name]').forEach(x=>x.name=`variants[${n}][${x.dataset.name}]`);document.querySelector('#variants').append(t)}</script>
